/* ── Candidate Card ── */
type CandidateCardProps = {
  candidate: Candidate
  onVote: (id: number) => void
  hasVoted: boolean
  votedFor: number | null
  allComments: Record<number, Comment[]>
}

function CandidateCard({ candidate, onVote, hasVoted, votedFor, allComments }: CandidateCardProps) {
  const isVotedFor = votedFor === candidate.id;
  const comments = allComments[candidate.id] || [];
  return (
    <div style={{background:"#fff",borderRadius:20,border:isVotedFor?"2px solid #1a1a1a":"1px solid #e5e5e3",boxShadow:isVotedFor?"0 8px 32px rgba(0,0,0,0.1)":"0 2px 12px rgba(0,0,0,0.04)",display:"flex",flexDirection:"column",height:"100%"}}>
      <div style={{padding:"24px 24px 0",textAlign:"center"}}>
        <div style={{width:"100%",maxWidth:200,margin:"0 auto 16px",aspectRatio:"1/1",borderRadius:16,overflow:"hidden",background:"#f0f0ee"}}>
          <img src={PHOTOS[candidate.id]} alt={candidate.name} style={{width:"100%",height:"100%",objectFit:"cover",objectPosition:"top center",display:"block"}} />
        </div>
        <div style={{display:"flex",alignItems:"center",justifyContent:"center",gap:8,flexWrap:"wrap",marginBottom:12}}>
          <h3 style={{fontSize:17,fontWeight:800,color:"#1a1a1a"}}>{candidate.name}</h3>
          <span style={{padding:"3px 10px",background:"#f5f5f3",color:"#6b6b6b",borderRadius:100,fontSize:12,fontWeight:600}}>{candidate.position}</span>
          {isVotedFor && <span style={{padding:"4px 10px",background:"#1a1a1a",color:"#fff",borderRadius:100,fontSize:11,fontWeight:700,display:"inline-flex",alignItems:"center",gap:4}}><CheckCircle2 size={11} /> MY PICK</span>}
        </div>
        <div style={{background:"#fdf6e8",borderRadius:12,padding:"12px 14px",textAlign:"left"}}>
          <p style={{fontSize:11,fontWeight:700,color:"#c99a2e",marginBottom:4,textTransform:"uppercase",letterSpacing:"0.06em"}}>✨ 가장 잘한 점</p>
          <p style={{fontSize:13,color:"#7a5c1a",lineHeight:1.65}}>{candidate.bestPoint}</p>
        </div>
      </div>
      <div style={{borderTop:"1px solid #f0f0ee",padding:"20px 24px",background:"#fafafa",flex:1,display:"flex",flexDirection:"column",gap:16}}>
        <div>
          <h4 style={{fontSize:12,fontWeight:700,color:"#1a1a1a",marginBottom:8,display:"flex",alignItems:"center",gap:6}}>
            <span style={{width:5,height:5,background:"#1a1a1a",borderRadius:"50%",display:"inline-block"}}/>핵심 기여 활동
          </h4>
          <ul style={{display:"flex",flexDirection:"column",gap:6,listStyle:"none",padding:0}}>
            {candidate.action.map((a,i)=>(
              <li key={i} style={{fontSize:12.5,color:"#5a5a5a",display:"flex",gap:8,alignItems:"flex-start",lineHeight:1.6}}>
                <span style={{color:"#ccc",flexShrink:0}}>›</span>{a}
              </li>
            ))}
          </ul>
        </div>
        <div style={{background:"#fff",borderRadius:10,padding:"14px 16px",border:"1px solid #ebebeb",display:"flex",flexDirection:"column",gap:10}}>
          <div>
            <p style={{fontSize:11,fontWeight:700,color:"#c0392b",marginBottom:4}}>마이너스 요인</p>
            <p style={{fontSize:12.5,color:"#5a5a5a",lineHeight:1.6}}>{candidate.minusFactor.problem}</p>
          </div>
          <div style={{borderTop:"1px solid #f0f0ee",paddingTop:10}}>
            <p style={{fontSize:11,fontWeight:700,color:"#27ae60",marginBottom:4}}>대응 조치</p>
            <p style={{fontSize:12.5,color:"#5a5a5a",lineHeight:1.6}}>{candidate.minusFactor.action}</p>
          </div>
        </div>
        {comments.length > 0 && (
          <div style={{borderTop:"1px solid #ebebeb",paddingTop:14}}>
            <div style={{display:"flex",alignItems:"center",gap:6,marginBottom:10}}>
              <MessageCircle size={13} color="#9a9a9a" /><span style={{fontSize:12,fontWeight:700,color:"#6b6b6b"}}>소감 {comments.length}개</span>
            </div>
            <div style={{display:"flex",flexDirection:"column",gap:8,maxHeight:160,overflowY:"auto"}}>
              {comments.map((c: Comment)=>(
                <div key={c.id} style={{background:"#fff",borderRadius:10,padding:"10px 12px",border:"1px solid #ebebeb"}}>
                  <div style={{display:"flex",alignItems:"center",gap:8,marginBottom:4}}>
                    <div style={{width:22,height:22,background:"#1a1a1a",borderRadius:"50%",display:"flex",alignItems:"center",justifyContent:"center"}}>
                      <span style={{fontSize:10,fontWeight:700,color:"#fff"}}>{c.nickname[0]}</span>
                    </div>
                    <span style={{fontSize:12,fontWeight:700,color:"#1a1a1a"}}>{c.nickname}</span>
                    <span style={{fontSize:11,color:"#bbb"}}>{new Date(c.createdAt).toLocaleTimeString("ko-KR",{hour:"2-digit",minute:"2-digit"})}</span>
                  </div>
                  <p style={{fontSize:12.5,color:"#5a5a5a",lineHeight:1.6}}>{c.content}</p>
                </div>
              ))}
            </div>
          </div>
        )}
      </div>
      <div style={{padding:"16px 24px"}}>
        {!hasVoted ? (
          <button onClick={()=>onVote(candidate.id)}
            style={{width:"100%",padding:14,borderRadius:12,border:"none",background:"#1a1a1a",color:"#fff",fontSize:14,fontWeight:700,cursor:"pointer",display:"flex",alignItems:"center",justifyContent:"center",gap:8}}
            onMouseEnter={e=>e.currentTarget.style.background="#333"}
            onMouseLeave={e=>e.currentTarget.style.background="#1a1a1a"}
          ><Vote size={16} /> 이 사람에게 투표</button>
        ) : (
          <div style={{width:"100%",textAlign:"center",padding:14,borderRadius:12,background:isVotedFor?"#1a1a1a":"#f5f5f3",color:isVotedFor?"#fff":"#bbb",fontSize:14,fontWeight:700}}>
            {isVotedFor?"✓ My Pick":"—"}
          </div>
        )}
      </div>
    </div>
  );
}

