type VotingDashboardProps = {
  votes: Record<number, number>
  totalVotes: number
  votedFor: number | null
}

function VotingDashboard({ votes, totalVotes, votedFor }: VotingDashboardProps) {
  const sorted = [...CANDIDATES].sort((a,b)=>(votes[b.id]||0)-(votes[a.id]||0));
  const maxVotes = Math.max(...Object.values(votes), 1);
  return (
    <section style={{maxWidth:960,margin:"0 auto 40px",padding:"0 24px"}}>
      <div style={{background:"#fff",borderRadius:16,border:"1px solid #e5e5e3",padding:"28px 32px"}}>
        <div style={{display:"flex",alignItems:"center",gap:12,marginBottom:24}}>
          <div style={{width:40,height:40,background:"#f5f5f3",borderRadius:10,display:"flex",alignItems:"center",justifyContent:"center"}}><BarChart3 size={18} color="#1a1a1a" /></div>
          <div>
            <h2 style={{fontSize:17,fontWeight:700,color:"#1a1a1a"}}>실시간 투표 결과</h2>
            <p style={{fontSize:13,color:"#9a9a9a"}}>총 {totalVotes}표</p>
          </div>
        </div>
        {totalVotes===0 ? (
          <div style={{textAlign:"center",padding:"40px 0",color:"#bbb"}}>
            <p style={{fontWeight:600,marginBottom:4}}>아직 투표가 없습니다</p>
            <p style={{fontSize:13}}>위의 후보자에게 투표해주세요!</p>
          </div>
        ) : (
          <div style={{display:"flex",flexDirection:"column",gap:12}}>
            {sorted.map((c,idx)=>{
              const count=votes[c.id]||0;
              const pct=totalVotes>0?Math.round((count/totalVotes)*100):0;
              const bar=Math.round((count/maxVotes)*100);
              const isVoted=votedFor===c.id;
              const isFirst=idx===0&&count>0;
              return (
                <div key={c.id} style={{display:"flex",alignItems:"center",gap:14,padding:"14px 16px",borderRadius:12,background:isVoted?"#f5f5f3":"#fafafa",border:isVoted?"1.5px solid #1a1a1a":"1px solid transparent"}}>
                  <div style={{width:30,height:30,borderRadius:"50%",flexShrink:0,display:"flex",alignItems:"center",justifyContent:"center",background:isFirst?"#e8b84b":"#ebebeb",fontWeight:800,fontSize:13,color:isFirst?"#1a1a1a":"#9a9a9a"}}>
                    {isFirst?<Award size={15}/>:idx+1}
                  </div>
                  <img src={PHOTOS[c.id]} alt={c.name} style={{width:40,height:40,borderRadius:"50%",objectFit:"cover",objectPosition:"top",flexShrink:0}}/>
                  <div style={{flex:1,minWidth:0}}>
                    <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:8}}>
                      <div style={{display:"flex",alignItems:"center",gap:8}}>
                        <span style={{fontWeight:700,fontSize:14,color:"#1a1a1a"}}>{c.name}</span>
                        <span style={{fontSize:12,color:"#bbb"}}>{c.position}</span>
                        {isVoted&&<span style={{fontSize:11,fontWeight:700,color:"#1a1a1a",background:"#e8b84b",padding:"2px 8px",borderRadius:100}}>MY PICK</span>}
                      </div>
                      <div style={{display:"flex",alignItems:"baseline",gap:2}}>
                        <span style={{fontSize:20,fontWeight:800,color:"#1a1a1a"}}>{pct}</span>
                        <span style={{fontSize:12,color:"#bbb"}}>%</span>
                        <span style={{fontSize:12,color:"#ccc",marginLeft:4}}>({count}표)</span>
                      </div>
                    </div>
                    <div style={{width:"100%",background:"#ebebeb",borderRadius:100,height:6}}>
                      <div style={{height:6,borderRadius:100,background:isFirst?"#1a1a1a":"#c8c8c8",width:`${bar}%`,transition:"width 1s ease"}}/>
                    </div>
                  </div>
                </div>
              );
            })}
          </div>
        )}
      </div>
    </section>
  );
}

/* ── 소감 ── */
type CommentSectionProps = {
  comments: Comment[]
  onAdd: (txt: string) => void
  hasVoted: boolean
}
function CommentSection({ comments, onAdd, hasVoted }: CommentSectionProps) {
  const [val, setVal] = useState("");
  const submit = () => { if(val.trim()){onAdd(val.trim());setVal("");} };
  return (
    <section style={{maxWidth:960,margin:"0 auto 48px",padding:"0 24px"}}>
      <div style={{background:"#fff",borderRadius:16,border:"1px solid #e5e5e3",padding:"28px 32px"}}>
        <div style={{display:"flex",alignItems:"center",gap:10,marginBottom:6}}>
          <Send size={18} color="#1a1a1a" />
          <h2 style={{fontSize:17,fontWeight:700,color:"#1a1a1a"}}>ACT 캠페인 참여 소감</h2>
          <span style={{fontSize:13,color:"#bbb"}}>{comments.length}개</span>
        </div>
        <p style={{fontSize:13.5,color:"#9a9a9a",lineHeight:1.7,marginBottom:20}}>
          색다른 방식의 ACT 캠페인, 어떠셨나요? 새롭게 느낀 점, 인상 깊었던 것, '책임'에 대해 다시 생각하게 된 부분이 있다면 자유롭게 나눠주세요!
        </p>
        {!hasVoted && (
          <div style={{marginBottom:16,padding:"12px 16px",background:"#fdf6e8",borderRadius:10,fontSize:13.5,color:"#a07820",fontWeight:600}}>
            💡 투표 후 소감을 남길 수 있습니다.
          </div>
        )}
        <div style={{display:"flex",gap:10,marginBottom:20}}>
          <input type="text" value={val} onChange={e=>setVal(e.target.value)}
            onKeyDown={e=>e.key==="Enter"&&submit()}
            placeholder="오늘 ACT 캠페인 참여 소감을 한 줄로 남겨주세요..."
            disabled={!hasVoted} maxLength={120}
            style={{flex:1,padding:"13px 18px",borderRadius:10,border:"1.5px solid #e5e5e3",fontSize:14,outline:"none",background:!hasVoted?"#fafafa":"#fff",color:"#1a1a1a"}}
          />
          <button onClick={submit} disabled={!val.trim()||!hasVoted}
            style={{padding:"13px 20px",borderRadius:10,border:"none",background:val.trim()&&hasVoted?"#1a1a1a":"#ebebeb",color:val.trim()&&hasVoted?"#fff":"#bbb",cursor:val.trim()&&hasVoted?"pointer":"not-allowed",display:"flex",alignItems:"center"}}
          ><Send size={16} /></button>
        </div>
        <div style={{display:"flex",flexDirection:"column",gap:10,maxHeight:280,overflowY:"auto"}}>
          {comments.length===0 ? (
            <p style={{textAlign:"center",color:"#bbb",fontSize:13.5,padding:"24px 0"}}>아직 소감이 없습니다. 첫 번째로 남겨보세요!</p>
          ) : comments.map((c: Comment)=>(
            <div key={c.id} style={{display:"flex",gap:12,padding:"14px 16px",background:"#fafafa",borderRadius:12}}>
              <div style={{width:36,height:36,background:"#1a1a1a",borderRadius:"50%",display:"flex",alignItems:"center",justifyContent:"center",flexShrink:0}}>
                <span style={{fontSize:13,fontWeight:700,color:"#fff"}}>{c.nickname[0]}</span>
              </div>
              <div style={{flex:1}}>
                <div style={{display:"flex",alignItems:"center",gap:8,marginBottom:4}}>
                  <span style={{fontSize:13,fontWeight:700,color:"#1a1a1a"}}>{c.nickname}</span>
                  {c.votedFor&&<span style={{fontSize:12,color:"#e8b84b",fontWeight:600}}>→ {CANDIDATES.find(x=>x.id===c.votedFor)?.name} 투표</span>}
                  <span style={{fontSize:12,color:"#ccc"}}>{new Date(c.createdAt).toLocaleTimeString("ko-KR",{hour:"2-digit",minute:"2-digit"})}</span>
                </div>
                <p style={{fontSize:13.5,color:"#5a5a5a",lineHeight:1.65}}>{c.content}</p>
              </div>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
}

/* ── Main App ── */
export default function App() {
  const [user, setUser] = useState<User>(() => {
    const saved = localStorage.getItem("act_user");
    return saved ? JSON.parse(saved) : {nickname: null, hasVoted: false, votedFor: null};
  });
  const [votes, setVotes] = useState<Record<number, number>>({1:0,2:0,3:0,4:0});
  const [candComments, setCandComments] = useState<Record<number, Comment[]>>({1:[],2:[],3:[],4:[]});
  const [globalComments, setGlobalComments] = useState<Comment[]>([]);
  const [loading, setLoading] = useState(true);
  const [confetti, setConfetti] = useState(false);
  const [voteComment, setVoteComment] = useState<string>("");
  const [pending, setPending] = useState<number | null>(null);
  const [showModal, setShowModal] = useState(false);

  // 초기 로드 — storage에서 데이터 불러오기
  useEffect(() => {
    (async () => {
      const [v, cc, gc] = await Promise.all([
        loadShared(KEYS.votes, {1:0,2:0,3:0,4:0}),
        loadShared(KEYS.candComments, {1:[],2:[],3:[],4:[]}),
        loadShared(KEYS.globalComments, []),
      ]);
      setVotes(v);
      setCandComments(cc);
      setGlobalComments(gc);
      setLoading(false);
    })();
  }, []);

  const totalVotes = Object.values(votes).reduce((s,v)=>s+v,0);

  const handleNickname = useCallback((nick: string) => {
    setUser(p => {
      const updated = {...p, nickname: nick};
      localStorage.setItem("act_user", JSON.stringify(updated));
      return updated;
    });
  }, []);
  const handleVoteClick = useCallback((id: number)=>{setPending(id);setShowModal(true);}, []);

  const handleConfirm = useCallback(async () => {
    if (!pending) return;
    const txt = voteComment.trim();
    const newUser = { ...user, hasVoted: true, votedFor: pending };
  
    await runTransaction(db, async (transaction) => {
      const votesRef = doc(db, "petit-act", KEYS.votes);
      const ccRef = doc(db, "petit-act", KEYS.candComments);

      // ✅ 먼저 모든 read
      const votesSnap = await transaction.get(votesRef);
      const ccSnap = await transaction.get(ccRef);

      const latestVotes = votesSnap.exists()
        ? (votesSnap.data().value as Record<number, number>)
        : { 1: 0, 2: 0, 3: 0, 4: 0 };

      const latestCC = ccSnap.exists()
        ? (ccSnap.data().value as Record<number, Comment[]>)
        : { 1: [], 2: [], 3: [], 4: [] };

      // 계산
      const newVotes = { ...latestVotes, [pending]: (latestVotes[pending] || 0) + 1 };

      // ✅ write는 나중
      transaction.set(votesRef, { value: newVotes });
      setVotes(newVotes);

      if (txt) {
        const nc: Comment = {
          id: crypto.randomUUID(),
          nickname: user.nickname || "",
          content: txt,
          createdAt: Date.now(),
          votedFor: pending,
        };

        const newCC = { ...latestCC, [pending]: [nc, ...(latestCC[pending] || [])] };

        transaction.set(ccRef, { value: newCC });
        setCandComments(newCC);
      }
    });
  
    setUser(newUser);
    localStorage.setItem("act_user", JSON.stringify(newUser));
    setConfetti(true);
    setTimeout(() => setConfetti(false), 2500);
    setShowModal(false); setVoteComment(""); setPending(null);
  }, [pending, voteComment, user]);

  const handleGlobalComment = useCallback(async (txt: string) => {
    const nc = {id:crypto.randomUUID(),nickname:user.nickname||"",content:txt,createdAt:Date.now(),votedFor:user.votedFor};
    const updated = [nc, ...globalComments];
    setGlobalComments(updated);
    await saveShared(KEYS.globalComments, updated);
  }, [user.nickname, user.votedFor, globalComments]);

  if(loading) return (
    <div style={{minHeight:"100vh",display:"flex",alignItems:"center",justifyContent:"center",background:"#f8f8f6"}}>
      <FontStyle/>
      <p style={{fontSize:16,color:"#9a9a9a",fontWeight:600}}>불러오는 중...</p>
    </div>
  );

  if(!user.nickname) return <><FontStyle/><NicknameModal onSubmit={handleNickname}/></>;

  const pendingCandidate = CANDIDATES.find(c=>c.id===pending);

  return (
    <div style={{minHeight:"100vh",background:"#f8f8f6"}}>
      <FontStyle/>
      <style>{`@keyframes cb{from{transform:translateY(0) scale(1)}to{transform:translateY(-24px) scale(1.1)}}`}</style>

      {confetti&&(
        <div style={{position:"fixed",inset:0,pointerEvents:"none",zIndex:50,display:"flex",alignItems:"center",justifyContent:"center"}}>
          <Trophy size={80} color="#e8b84b" style={{animation:"cb 0.5s infinite alternate"}}/>
        </div>
      )}

      {showModal&&pendingCandidate&&(
        <div style={{position:"fixed",inset:0,background:"rgba(0,0,0,0.5)",backdropFilter:"blur(8px)",display:"flex",alignItems:"center",justifyContent:"center",zIndex:50,padding:16}}>
          <div style={{background:"#fff",borderRadius:20,padding:36,width:"100%",maxWidth:440,boxShadow:"0 24px 64px rgba(0,0,0,0.15)"}}>
            <div style={{textAlign:"center",marginBottom:24}}>
              <div style={{width:80,height:80,borderRadius:"50%",overflow:"hidden",margin:"0 auto 14px",background:"#f5f5f3"}}>
                <img src={PHOTOS[pendingCandidate.id]} alt={pendingCandidate.name} style={{width:"100%",height:"100%",objectFit:"cover",objectPosition:"top"}}/>
              </div>
              <h2 style={{fontSize:19,fontWeight:800,color:"#1a1a1a",marginBottom:6}}>
                <span style={{color:"#e8b84b"}}>{pendingCandidate.name}</span>에게 투표할게요!
              </h2>
              <p style={{fontSize:13.5,color:"#9a9a9a"}}>왜 이 분이 '책임'의 아이콘인가요? 한 줄로 남겨주세요.</p>
            </div>
            <textarea value={voteComment} onChange={e=>setVoteComment(e.target.value)}
              placeholder="예) 실수를 숨기지 않고 즉시 공유한 점이 진정한 책임이라고 생각해요."
              rows={3} maxLength={120}
              style={{width:"100%",padding:"14px 16px",borderRadius:12,border:"1.5px solid #e5e5e3",fontSize:14,resize:"none",outline:"none",boxSizing:"border-box",lineHeight:1.6,display:"block"}}
            />
            <p style={{fontSize:12,color:"#ccc",textAlign:"right",marginBottom:20}}>{voteComment.length}/120</p>
            <div style={{display:"flex",gap:10}}>
              <button onClick={()=>{setShowModal(false);setVoteComment("");setPending(null);}}
                style={{flex:1,padding:14,borderRadius:12,border:"none",background:"#f5f5f3",color:"#6b6b6b",fontSize:14,fontWeight:700,cursor:"pointer"}}>취소</button>
              <button onClick={handleConfirm}
                style={{flex:1,padding:14,borderRadius:12,border:"none",background:"#1a1a1a",color:"#fff",fontSize:14,fontWeight:700,cursor:"pointer",display:"flex",alignItems:"center",justifyContent:"center",gap:8}}>
                <Vote size={16}/> 투표하기
              </button>
            </div>
          </div>
        </div>
      )}

      <header style={{background:"rgba(255,255,255,0.9)",backdropFilter:"blur(12px)",borderBottom:"1px solid #e5e5e3",position:"sticky",top:0,zIndex:40}}>
        <div style={{maxWidth:960,margin:"0 auto",padding:"12px 24px",display:"flex",alignItems:"center",justifyContent:"space-between"}}>
          <div style={{display:"flex",alignItems:"center",gap:10}}>
            <div style={{width:32,height:32,background:"#1a1a1a",borderRadius:8,display:"flex",alignItems:"center",justifyContent:"center"}}><Award size={16} color="#e8b84b"/></div>
            <span style={{fontSize:14,fontWeight:700,color:"#1a1a1a"}}>ACT Campaign</span>
          </div>
          <div style={{display:"flex",alignItems:"center",gap:10}}>
            {user.hasVoted&&<span style={{fontSize:12,fontWeight:700,color:"#3d9a5c",background:"#e6f4ec",padding:"4px 12px",borderRadius:100}}>✓ 투표 완료</span>}
            <div style={{display:"flex",alignItems:"center",gap:8,padding:"6px 14px",background:"#f5f5f3",borderRadius:100}}>
              <UserCircle size={15} color="#6b6b6b"/>
              <span style={{fontSize:13,fontWeight:700,color:"#1a1a1a"}}>{user.nickname}</span>
            </div>
          </div>
        </div>
      </header>

      <HeroSection/>
      <ResponsibilitySection/>
      <ScenarioSection/>

      <section style={{maxWidth:1400,margin:"0 auto 48px",padding:"0 24px"}}>
        <div style={{textAlign:"center",marginBottom:32}}>
          <h2 style={{fontSize:22,fontWeight:800,color:"#1a1a1a",marginBottom:8}}>후보자</h2>
          <p style={{fontSize:14.5,color:"#9a9a9a"}}>엘리시아 핵심가치의 <strong style={{color:"#1a1a1a"}}>"책임"</strong>을 가장 잘 보여준 사람에게 투표해주세요!</p>
        </div>
        <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fit,minmax(280px,1fr))",gap:20}}>
          {CANDIDATES.map(c=>(
            <CandidateCard key={c.id} candidate={c} onVote={handleVoteClick}
              hasVoted={user.hasVoted} votedFor={user.votedFor} allComments={candComments}/>
          ))}
        </div>
      </section>

      <VotingDashboard votes={votes} totalVotes={totalVotes} votedFor={user.votedFor}/>
      <CommentSection comments={globalComments} onAdd={handleGlobalComment} hasVoted={user.hasVoted}/>

      <footer style={{background:"#1a1a1a",color:"rgba(255,255,255,0.3)",textAlign:"center",padding:"28px 24px"}}>
        <p style={{fontSize:13}}>Elyssia ACT Campaign — Responsibility Challenge</p>
      </footer>
    </div>
  );
}
